const Get=function(){var r={};var g=location.search.replace('?','').split('&',-1);for(var i=0;i<g.length;i++){var _g=g[i].split('=');if(_g[0]!=''){r[_g[0]]=_g[1]}}return r;}();
class Modules {constructor(){this.b=document.getElementById('Modules');if(!this.b){this.b=new Elements('div',document.head,{id:'Modules'});}};add(p,n,c){try{return new Elements('script',this.b,{type:c,src:`${location.origin}/${p}/${n}`})}catch(err){console.error(err);return undefined;}};adds(p,n,c){try{return new Elements('link',this.b,{rel:c,href:`${location.origin}/${p}/${n}`})}catch(err){console.error(err);return undefined;}}};self.M = new Modules();
const setCookie=(cname,cvalue,exdays)=>{const d=new Date();d.setTime(d.getTime()+(exdays*24*60*60*1000));let expires="expires="+d.toUTCString();document.cookie=`${cname}=${cvalue};${expires};path=/`;};
const getCookie=(cname)=>{let name=cname+"=";let ca=decodeURIComponent(document.cookie).split(';');for(let i=0;i<ca.length;i++){let c=ca[i];while(c.charAt(0)==' '){c=c.substring(1);}if(c.indexOf(name)==0){return c.substring(name.length,c.length);}}return undefined;};const gi=(i)=>{return document.getElementById(i)};const gbc=(i)=>{return document.getElementsByClassName(i)};
const send=async(u,v={},h={})=>{var y=u;for(var k in v){y+=`${(y==u?'?':'&')}${k}=${v[k]}`;};return await s(y, h);};const s = async (u,h={})=>{const r=await fetch(u,h);if(!r.ok){console.error(`${r.status} on ${r.url}`);return null;}return r;};
const stj=(r,c)=>{r.json().then((t=>{c(t)})).catch((err=>{console.error(err)}))};
async function m(M){Mv();for(var m of M){if(m.t==='script'){var t=self.M.add(m.p,m.n,m.c);self.Ms[m.n]=false;}else if(m.t==='style'){self.M.adds(m.p,m.n,m.c);}}};
function Mv(){setInterval(()=>{var o=true;for(var k in self.Ms){if(!self.Ms[k]){o=false;}};document.getElementById('loading').style.display=o?'none':'block';document.getElementById('after-loading').style.display=!o?'none':'block';}, 10);}
